    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Tutoría$$, $$CEDE1022$$,
        3, 4,
        FALSE, $$specific$$,
        $$El curso de “Tutoría” tiene como resultado de aprendizaje el desarrollo de las capacidades “Desarrolla acciones de orientación tutorial grupal que atienda las necesidades sociales, cognitivas y emocionales de los estudiantes de manera preventiva ” y “Promueve la orientación y acción tutorial individual en base a las necesidades específicas de los estudiantes, haciendo partícipe al entorno familiar” , que contribuye a la competencia de especialidad “Promueve acciones de orientación tutorial como parte del acompañamiento psicopedagógico inherente al proceso formativo del estudiante garantizando su bienestar y el desarrollo de competencias socio afectivas y cognitivas”, según perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Plantea actividades que posibiliten el conocimiento de : diagnóstico psicopedagógico; instrumentos para la detección y diagnóstico de necesidades tutoriales: test, cuestionarios, encuestas y el diario; enfoques de la tutoría: vocacional, educativo y de asesoramiento; Enfoques de la orientación: paternalista, basado en la libertad y el dialógico; características de la tutoría: formativa, preventiva, personalizada, integral, inclusiva y regeneradora; instrumentos de intervención tutorial: la observación, el autodiagnóstico, la entrevista, etc.; áreas de la tutoría: personal–social, académica, vocacional, salud corporal y mental, ayuda social, cultura y actualidad, convivencia y disciplina escolar; características del plan tutorial; elementos del plan tutorial: fundamentación, objetivos, actividades, recursos, evaluación; estrategias de monitoreo y acompañamiento tutorial; técnicas e instrumentos de evaluación tutorial; instrumentos para la detección y diagnóstico de necesidades tutoriales: test, cuestionarios, encuestas y el diario; características de la tutoría: personal y familiar, instrumentos de intervención tutorial; estrategias de acción tutorial y técnicas e instrumentos de evaluación tutorial individual y desarrolla las habilidades de: diagnostica necesidades de atención; analiza resultados en función a la aplicación de instrumentos; explica los enfoques y características de la tutoría y de la orientación tutorial; analiza la propuesta y las características de los enfoques de la tutoría y orientación; determina y reconoce las características de los instrumentos de intervención tutorial; tipifica las principales áreas de la tutoría; elabora planes de orientación e intervención tutorial; aplica estrategias efectivas de monitoreo y acompañamiento tutorial; determina y utiliza técnicas e instrumentos de evaluación tutorial pertinentes; diagnostica necesidades de atención; analiza resultados en función a la aplicación de instrumentos; explica y determina las características de la tutoría personal y familiar; identifica los instrumentos de intervención tutorial personal y familiar, selecciona los instrumentos pertinentes en los procesos de intervención; caracteriza las principales áreas de la tutoría; selecciona y ejecuta estrategias de acción tutorial personal y familiar; selecciona técnicas pertinentes a los procesos de atención e intervención y aplica instrumentos para la evaluación tutorial personal y familiar.$$,
        $$Promueve acciones de orientación tutorial como parte del acompañamiento psicopedagógico inherente al proceso formativo del estudiante garantizando su bienestar y el desarrollo de competencias socio afectivas y cognitivas$$,
        $$Desarrolla acciones de orientación tutorial grupal que atienda las necesidades sociales, cognitivas y emocionales de los estudiantes de manera preventiva ” y “Promueve la orientación y acción tutorial individual en base a las necesidades específicas de los estudiantes, haciendo partícipe al entorno familiar$$,
        $$Tiene la capacidad de desarrolla acciones de orientación tutorial grupal que atienda las necesidades sociales, cognitivas y emocionales de los estudiantes de manera preventiva ” y “Promueve la orientación y acción tutorial individual en base a las necesidades específicas de los estudiantes, haciendo partícipe al entorno familiar$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDE1022$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Fisiología del ejercicio$$, $$CEDS1084$$,
        3, 4,
        FALSE, $$specialty$$,
        $$El curso “Fisiología del ejercicio” tiene como resultado de aprendizaje la capacidad “Desarrolla los procesos bioenergéticos, los sistemas energéticos en el ejercicio físico, la función y resíntesis del ATP durante la actividad de contracción muscular y los diferentes tipos de adaptaciones que la actividad física provoca en órganos sistemas y tejidos, y en todo el organismo humano manteniendo r y preservando la salud.”, contribuye al desarrollo de la competencia “Ejecutar programas de enseñanza aprendizaje para el desarrollo, la estructura y función, nutrición, evaluación de la composición corporal y de la condición física, de los primeros auxilios, seleccionando protocolos de seguridad y responsabilidad para preservar y mantener la salud” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Desarrolla contenidos como: Historia y conceptualización de la fisiología del ejercicio. Reservas energéticas. El Glucógeno. Concentración del glucógeno y sus consecuencias para el rendimiento. Ritmo de oxidación del glucógeno muscular. Resíntesis o restitución del Glucógeno. Triglicéridos. Oxidación del glicógeno y las grasas durante el ejercicio. La fosfocreatina. Las proteínas. El ejercicio físico. Clasificación, fases: Las fibras musculares y su reclutamiento, forma de incremento de acuerdo con el tipo de entrenamiento físico La Bioenergética: Los sistemas energéticos: La vía anaeróbica aláctica, la vía anaeróbica láctica, la vía aeróbica. Energía, estructura y función del ATP. Continuum Energético. Interacción de los sistemas. Sistema de los fosfágenos. Sistema Glucolico, Sistema Aeróbico. Teoría Schult de Lactato. Entrenamiento por áreas funcionales anaeróbicas. Entrenamiento por áreas funcionales aeróbicas. El consumo máximo de oxígeno. La inadaptación, adaptaciones orgánicas con el ejercicio, adaptaciones metabólicas, musculares, circulatorias, cardiacas, respiratorias, en la sangre, en el medio interno, en el sistema cardiovascular, a fin de mantener y preservar la salud.$$,
        $$Ejecutar programas de enseñanza aprendizaje para el desarrollo, la estructura y función, nutrición, evaluación de la composición corporal y de la condición física, de los primeros auxilios, seleccionando protocolos de seguridad y responsabilidad para preservar y mantener la salud$$,
        $$Desarrolla los procesos bioenergéticos, los sistemas energéticos en el ejercicio físico, la función y resíntesis del ATP durante la actividad de contracción muscular y los diferentes tipos de adaptaciones que la actividad física provoca en órganos sistemas y tejidos, y en todo el organismo humano manteniendo r y preservando la salud.$$,
        $$Tiene la capacidad de desarrolla los procesos bioenergéticos, los sistemas energéticos en el ejercicio físico, la función y resíntesis del ATP durante la actividad de contracción muscular y los diferentes tipos de adaptaciones que la actividad física provoca en órganos sistemas y tejidos, y en todo el organismo humano manteniendo r y preservando la salud.$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1084$$);

    INSERT INTO courses
