    SELECT
        v_program_id, $$Primeros auxilios$$, $$CEDS1085$$,
        3, 4,
        FALSE, $$specialty$$,
        $$El curso “Primeros auxilios” tiene como resultado de aprendizaje la capacidad “Ejecuta procesos de primeros auxilios ante situaciones de emergencia y catástrofe, aplicando normas y procedimientos de valoración general ante la víctima y tomando las precauciones como auxiliador, actuando con seguridad y responsabilidad para preservar la vida.”, contribuye al desarrollo de la competencia “Ejecutar programas de enseñanza aprendizaje para el desarrollo, la estructura y función, nutrición, evaluación de la composición corporal y de la condición física, de los primeros auxilios, seleccionando protocolos de seguridad y responsabilidad para preservar y mantener la salud” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone actividades como trabajo individual, trabajo cooperativo, prácticas dirigidas y experiencias de campo; que posibiliten el conocimiento sobre los primeros Auxilios: Conceptualización: Objetivos. Aplica normas generales para prestar los primeros auxilios. Ejecuta la valoración de un lesionado. Toma las precauciones generales para prestar los primeros auxilios. Aplica técnicas y procedimientos adecuados y vigentes en lesiones del aparato cardiorrespiratorio, circulación, osteoarticular y muscular, en la introducción de cuerpos extraños, intoxicaciones, picaduras y mordeduras, enfermedades de aparición súbita, en traslado de víctimas, etc. demostrando seguridad y responsabilidad.$$,
        $$Ejecutar programas de enseñanza aprendizaje para el desarrollo, la estructura y función, nutrición, evaluación de la composición corporal y de la condición física, de los primeros auxilios, seleccionando protocolos de seguridad y responsabilidad para preservar y mantener la salud$$,
        $$Ejecuta procesos de primeros auxilios ante situaciones de emergencia y catástrofe, aplicando normas y procedimientos de valoración general ante la víctima y tomando las precauciones como auxiliador, actuando con seguridad y responsabilidad para preservar la vida.$$,
        $$Tiene la capacidad de ejecuta procesos de primeros auxilios ante situaciones de emergencia y catástrofe, aplicando normas y procedimientos de valoración general ante la víctima y tomando las precauciones como auxiliador, actuando con seguridad y responsabilidad para preservar la vida.$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1085$$);

    INSERT INTO courses
