    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Didáctica del juego educativo$$, $$CEDS1082$$,
        3, 4,
        FALSE, $$specialty$$,
        $$El curso “Didáctica del juego educativo” tiene como resultado de aprendizaje la capacidad “Ejecutar el proceso enseñanza aprendizaje de los juegos educativos; como un recurso didáctico para el aprendizaje y un medio para la formación; aplicando teorías, componentes para el desarrollo cognitivo, social, afectivo y psicomotor, clasificando a los juegos y ejecutándolos, valorando sus ventajas y el rol del docente en su práctica”, contribuye al desarrollo de la competencia “Ejecutar el proceso enseñanza aprendizaje de la Educación Física y de los deportes, aplicando diseños, enfoques, leyes, métodos, procedimientos y técnicas para el desarrollo de las habilidades motrices, las capacidades físicas, la psicomotricidad, los juegos, la gimnasia aeróbica, las danzas peruanas, el ejercicio físico, etc.; en los niveles de la Educación Básica Regular, para niños, jóvenes. demostrando eficiencia profesional” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone actividades como el juego de roles, trabajo individual, trabajo cooperativo, prácticas dirigidas, ejercitación y experiencias de campo; que posibiliten el conocimiento del juego: significados y conceptos. Algunas características del juego. El juego y su potencial formativo. El juego en el niño y la niña, un recurso didáctico para el aprendizaje y un medio para la formación. Clasificación de los juegos: Juegos sensoriales, motrices, anatómicos, Juegos de Desarrollo, Juegos predeportivos, Juegos Deportivos. Teorías del juego: de la energía excedente, del esparcimiento y la recreación, de la práctica del instinto (preparación para la vida futura), de la recapitulación, de la catarsis, de la auto expresión, como estimulante del crecimiento, del entretenimiento, como ejercicio complementario, del crecimiento y mejoramiento. de reconstrucción cognoscitiva. El juego como fuente de aprendizaje Ventajas y valores educativos del juego La importancia del juego en la infancia. El juego como recurso didáctico. Aplica juegos educativos tomando en cuenta su clasificación y sus componentes en el aprendizaje cognitivo, social, afectivo y psicomotor.$$,
        $$Ejecutar el proceso enseñanza aprendizaje de la Educación Física y de los deportes, aplicando diseños, enfoques, leyes, métodos, procedimientos y técnicas para el desarrollo de las habilidades motrices, las capacidades físicas, la psicomotricidad, los juegos, la gimnasia aeróbica, las danzas peruanas, el ejercicio físico, etc.; en los niveles de la Educación Básica Regular, para niños, jóvenes. demostrando eficiencia profesional$$,
        $$Ejecutar el proceso enseñanza aprendizaje de los juegos educativos; como un recurso didáctico para el aprendizaje y un medio para la formación; aplicando teorías, componentes para el desarrollo cognitivo, social, afectivo y psicomotor, clasificando a los juegos y ejecutándolos, valorando sus ventajas y el rol del docente en su práctica$$,
        $$Tiene la capacidad de ejecutar el proceso enseñanza aprendizaje de los juegos educativos; como un recurso didáctico para el aprendizaje y un medio para la formación; aplicando teorías, componentes para el desarrollo cognitivo, social, afectivo y psicomotor, clasificando a los juegos y ejecutándolos, valorando sus ventajas y el rol del docente en su práctica$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1082$$);

