    SELECT
        v_program_id, $$Dimensiones Sociológicas de Educación Física y Deporte$$, $$CEDS1083$$,
        3, 4,
        FALSE, $$specialty$$,
        $$El curso “Dimensiones sociológicas de educación física y deporte” tiene como resultado de aprendizaje la capacidad “Identifica la realidad social y su interrelación con la práctica de las actividades físicas y deportivas.”, contribuye al desarrollo de la competencia “Aplica procesos de emprendimiento de las actividades físicas y deportivas, de inclusión y práctica de actividades para olímpicas, y psicológicas para el desarrollo integral” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone actividades como trabajo individual, trabajo cooperativo, prácticas dirigidas, análisis de casos que posibiliten el conocimiento de la globalización y deporte, contenidos de la cultura (creencias, ideas, ideología, valores y normas), multiculturalidad y deporte, la masividad del movimiento deportivo y de la cultura física. Los esports y su impacto en la sociedad. Dimensiones sociológicas de la Educación física y deporte, grupos de edad, educación, raza y etnia, aspectos socioeconómicos, género, religión, aspectos políticos, organizaciones, calidad de vida. Juegos en las comunidades nativas del Perú y su desarrollo. Desarrolla habilidades para reflexionar y analiza la relación entre el individuo y la sociedad en sus diferentes contextos$$,
        $$Aplica procesos de emprendimiento de las actividades físicas y deportivas, de inclusión y práctica de actividades para olímpicas, y psicológicas para el desarrollo integral$$,
        $$Identifica la realidad social y su interrelación con la práctica de las actividades físicas y deportivas.$$,
        $$Tiene la capacidad de identifica la realidad social y su interrelación con la práctica de las actividades físicas y deportivas.$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1083$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Psicología del deporte$$, $$CEDS1086$$,
        3, 4,
        FALSE, $$specialty$$,
        $$El curso “Psicología del deporte” tiene como resultado de aprendizaje la capacidad “Describe los diversos procesos que brinda la psicología deportiva para el bienestar y salud mental de las personas”, contribuye al desarrollo de la competencia “Aplica procesos de emprendimiento de las actividades físicas y deportivas, de inclusión y práctica de actividades para olímpicas, y psicológicas para el desarrollo integral” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone actividades como trabajo individual, trabajo cooperativo, prácticas dirigidas, análisis de casos que posibiliten el conocimiento de la conducta humana en la actividad y el deporte. Dimensión afectiva y cognitivo, motivacional o dimensiones sensorias motoras. La preparación psicológica: motivación, personalidad, conflictos psicológicos, ansiedad, frustraciones, técnicas de apoyo y tratamiento, relajación, entrenamiento mental. Variables psicológicas relevantes en la actividad física y el deporte. Evaluación y diagnóstico, test y cuestionarios. Entrevistas, técnicas y procedimientos de auto, observación y auto registro, registros de observación y registros psicofisiológicos. Estudio de casos a nivel de deportistas y de equipos. Desarrolla habilidades para aplicar procesos psicológicos en la práctica de las actividades físicas y deportivas.$$,
        $$Aplica procesos de emprendimiento de las actividades físicas y deportivas, de inclusión y práctica de actividades para olímpicas, y psicológicas para el desarrollo integral$$,
        $$Describe los diversos procesos que brinda la psicología deportiva para el bienestar y salud mental de las personas$$,
        $$Tiene la capacidad de describe los diversos procesos que brinda la psicología deportiva para el bienestar y salud mental de las personas$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1086$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Teoría curricular$$, $$CEDE1005$$,
        3, 5,
        FALSE, $$specific$$,
        $$El curso de Teoría curricular tiene como resultado de aprendizaje el desarrollo de la capacidad “Analiza documentos curriculares como CNEBR, PEI, PAT y PCI, según fundamentos de la teoría curricular” y que contribuye al desarrollo de la competencia específica “Gestiona el proceso formativo en los distintos niveles del sistema educativo a partir del conocimiento de las principales características biopsicosociales de los estudiantes, teorías del desarrollo humano, teorías psicológicas, modelos pedagógicos, paradigmas curriculares, teorías del aprendizaje, modelos y enfoques de gestión educativa, lineamientos psicopedagógicos de orientación tutorial y de los procesos en la formulación de proyectos de promoción social”, según Perfil de Egreso. Es un curso de naturaleza teórico- práctica, enmarcado en el enfoque por competencias que posibilite una metodología activa en un entorno real de enseñanza y aprendizaje situando al estudiante como protagonista de su aprendizaje y el docente como facilitador del proceso formativo. Plantea actividades como exposiciones, debates, foros, estudio de casos, trabajo cooperativo y análisis de lecturas que posibiliten el conocimiento de Currículo Nacional de Educación Básica Regular, vinculación estratégica con el currículo departamental, el PEI, PAT, PCI, de la institución educativa, definiciones curriculares polisémicas, historia y alcance conceptual, tipos de currículos: carácter, enfoques, principales actores,(educativos, económicos, políticos y tecnológicos), principales teorías curriculares y modelos , metodología sistémica de elaboración de currículo: elementos, procesos y productos, el diseño como proceso y sus elementos, niveles de diversificación y las derivaciones del PCI, análisis y elaboración propositiva de los componentes curriculares, lineamientos operativos metodológicos, como se elabora los componentes curriculares: diagnóstico, perfil etc. Además, desarrolla habilidades vinculadas a identificar los puentes curriculares entre el currículo nacional y el currículo departamental, contrasta como se tributan el PEI, PAT, para el diseño del PCI, Identifica la concepción y la teoría curricular que maneja un docente, caracteriza los elementos del diseño curricular, analiza un componente curricular, propone la elaboración de los componentes curriculares, identifica las diferentes metodologías para levantar los componentes curriculares como propuesta, plantea sugerencias, para elaborar los componentes curriculares.$$,
        $$Gestiona el proceso formativo en los distintos niveles del sistema educativo a partir del conocimiento de las principales características biopsicosociales de los estudiantes, teorías del desarrollo humano, teorías psicológicas, modelos pedagógicos, paradigmas curriculares, teorías del aprendizaje, modelos y enfoques de gestión educativa, lineamientos psicopedagógicos de orientación tutorial y de los procesos en la formulación de proyectos de promoción social$$,
        $$Analiza documentos curriculares como CNEBR, PEI, PAT y PCI, según fundamentos de la teoría curricular$$,
        $$Tiene la capacidad de analiza documentos curriculares como CNEBR, PEI, PAT y PCI, según fundamentos de la teoría curricular$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDE1005$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Seminario de investigación cuantitativa$$, $$CEDE1006$$,
        3, 5,
        FALSE, $$specific$$,
        $$El curso de ”Seminario de Investigación Cuantitativa” tiene como resultado de aprendizaje la capacidad de “Planifica investigaciones educativas, con enfoque cuantitativo, considerando sus tipos, diseños y niveles investigativos, que permitan elaborar propuestas alternativas a los problemas educativos”, que contribuye a la competencia específica “Desarrolla investigaciones educativas en base a los diversos paradigmas, metodologías y enfoques investigativos, en los distintos ámbitos de su actuación, buscando contribuir con alternativas de solución, orientadas a la mejora de la educación”, según perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcado en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Plantea actividades que posibiliten el desarrollo del conocimiento: análisis del concepto de investigación, tipos y proyecto de investigación cuantitativa, desarrollando las habilidades: busca y procesa información procedente de fuentes científicas actualizadas, utiliza la metodología de la investigación científica, la lógica y otras disciplinas conexas con profundidad, sentido crítico y espíritu innovador.$$,
        $$Desarrolla investigaciones educativas en base a los diversos paradigmas, metodologías y enfoques investigativos, en los distintos ámbitos de su actuación, buscando contribuir con alternativas de solución, orientadas a la mejora de la educación$$,
        $$Planifica investigaciones educativas, con enfoque cuantitativo, considerando sus tipos, diseños y niveles investigativos, que permitan elaborar propuestas alternativas a los problemas educativos$$,
        $$Tiene la capacidad de planifica investigaciones educativas, con enfoque cuantitativo, considerando sus tipos, diseños y niveles investigativos, que permitan elaborar propuestas alternativas a los problemas educativos$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDE1006$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Desarrollo Profesional I: Comunidad y Escuela$$, $$CEDE1008$$,
        3, 5,
        FALSE, $$specific$$,
        $$El curso de Desarrollo Profesional I: Comunidad y Escuela tiene como resultado de aprendizaje el desarrollo de la capacidad “explica los contextos y las relaciones que existen entre los actores de la comunidad y la institución educativa, a partir de herramientas, métodos, y técnicas de investigación educativa etnográfica, con la finalidad de situar la profesión docente”, se orienta a desarrollar la competencia específica “promueve sesiones de aprendizaje situados, considerando el contexto y la cultura escolar, utilizando los principios de la docencia reflexiva para la mejora de su práctica; evaluando los procesos de gestión institucional, y proponiendo mejoras de su práctica docente, utilizando la metodología de Investigación Acción Pedagógica”. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Plantea actividades que posibiliten el conocimiento Escuela y comunidad, observación participante y no participante, construcción de instrumentos de observación, la encuesta como medio para observar la comunidad, cuestionario y escala de Likert, diálogos, historias y otras miradas entre la escuela y la comunidad, la entrevista en profundidad, el documental como estrategia de reflexión sobre la práctica; y, desarrolla las habilidades: Elabora instrumentos de investigación tales como entrevista, encuesta y relato etnográfico, procesa la información recogida. aplicando técnicas de sistematización. El producto acreditable consiste en la elaboración de un informe de observación sobre los vínculos entre la institución educativa y la comunidad, documentado con evidencias.$$,
        $$promueve sesiones de aprendizaje situados, considerando el contexto y la cultura escolar, utilizando los principios de la docencia reflexiva para la mejora de su práctica; evaluando los procesos de gestión institucional, y proponiendo mejoras de su práctica docente, utilizando la metodología de Investigación Acción Pedagógica$$,
        $$explica los contextos y las relaciones que existen entre los actores de la comunidad y la institución educativa, a partir de herramientas, métodos, y técnicas de investigación educativa etnográfica, con la finalidad de situar la profesión docente$$,
        $$Tiene la capacidad de explica los contextos y las relaciones que existen entre los actores de la comunidad y la institución educativa, a partir de herramientas, métodos, y técnicas de investigación educativa etnográfica, con la finalidad de situar la profesión docente$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDE1008$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Entrenamiento$$, $$CEDS1140$$,
        3, 5,
        FALSE, $$specialty$$,
        $$El curso “Entrenamiento”, tiene como resultado de aprendizaje la capacidad “Desarrolla los fundamentos básicos del entrenamiento físico, haciendo uso de diversos enfoques, leyes, principios, métodos técnicas y procedimientos, para utilizarlos como insumos en la elaboración de programas de entrenamiento físico a fin de provocar diversas adaptaciones en el organismo de niños, jóvenes, adultos y deportistas”, contribuye al desarrollo de la competencia “Ejecutar programas de entrenamiento de las capacidades físicas o funcionales; resistencia, velocidad, fuerza, flexibilidad, generando adaptaciones internas y externas en el organismo a fin de contribuir a preservar y mantener la salud y una buena calidad de vida” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone actividades como el trabajo individual, trabajo cooperativo y análisis de casos; que posibiliten el conocimiento del entrenamiento la conceptualización, tipos, entrenamiento físico, características del entrenamiento físico, capacidad potencial del Entrenamiento: conceptualización, tipos, entrenamiento físico, características del entrenamiento físico, capacidad potencial del entrenamiento, componentes funcionales, principios del entrenamiento, componentes de la carga, intensidad, volumen, duración, densidad, frecuencia, Tipos de entrenamiento físico. La flexibilidad, componentes de la flexibilidad, tipos de movilidad, factores limitantes de la movilidad. Aplica los principios básicos del entrenamiento de la flexibilidad, la sesión especial de flexibilidad, la flexibilidad como recurso a la vuelta a la calma, domina técnicas de facilitación neuromuscular propioceptiva.$$,
        $$Ejecutar programas de entrenamiento de las capacidades físicas o funcionales; resistencia, velocidad, fuerza, flexibilidad, generando adaptaciones internas y externas en el organismo a fin de contribuir a preservar y mantener la salud y una buena calidad de vida$$,
        $$Desarrolla los fundamentos básicos del entrenamiento físico, haciendo uso de diversos enfoques, leyes, principios, métodos técnicas y procedimientos, para utilizarlos como insumos en la elaboración de programas de entrenamiento físico a fin de provocar diversas adaptaciones en el organismo de niños, jóvenes, adultos y deportistas$$,
        $$Tiene la capacidad de desarrolla los fundamentos básicos del entrenamiento físico, haciendo uso de diversos enfoques, leyes, principios, métodos técnicas y procedimientos, para utilizarlos como insumos en la elaboración de programas de entrenamiento físico a fin de provocar diversas adaptaciones en el organismo de niños, jóvenes, adultos y deportistas$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1140$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Cineantropometría$$, $$CEDS1138$$,
        3, 5,
        FALSE, $$specialty$$,
        $$El curso “Cineantropometría” tiene como resultado de aprendizaje la capacidad “Ejecuta el método antropométrico en la determinación de la valoración corporal. Aplica instrumentos especiales para la toma de medidas antropométricas en niños, jóvenes, adultos etc. Aplica el método de la Somatoscopia en la construcción del modelo postural, identificando alteraciones y proponiendo entrenamientos preventivos para el cuidado postural”, contribuye al desarrollo de la competencia “Ejecutar programas de enseñanza aprendizaje para el desarrollo, la estructura y función, nutrición, evaluación de la composición corporal y de la condición física, de los primeros auxilios, seleccionando protocolos de seguridad y responsabilidad para preservar y mantener la salud” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone actividades como trabajo individual, trabajo cooperativo, prácticas dirigidas y experiencias de campo; que posibiliten el conocimiento de la historia de la cineantropometría, aplicaciones y métodos cineantropometricos: directos, indirectos y doblemente indirectos. La antropometría como método doblemente indirecto de valoración corporal, métodos para valorar la composición corporal. El IMC, el índice CC. Técnicas e instrumentos de medición: Peso, talla, perímetros, longitudes, diámetros, pliegues cutáneos. El Somatotipo, la Somatocarta y la clasificación del somatotipo. La Somatoscopia (postura). Fundamentos anatómicos. Modelo postural y sus factores que influyen en la postura. Alteraciones posturales en Educación física y postura corporal. Entrenamiento preventivo postural. Domina técnicas de medición antropométrica. Calcula la composición corporal: Tejido óseo. Muscular, tejido residual, y grasa corporal con seguridad y precisión.$$,
        $$Ejecutar programas de enseñanza aprendizaje para el desarrollo, la estructura y función, nutrición, evaluación de la composición corporal y de la condición física, de los primeros auxilios, seleccionando protocolos de seguridad y responsabilidad para preservar y mantener la salud$$,
        $$Ejecuta el método antropométrico en la determinación de la valoración corporal. Aplica instrumentos especiales para la toma de medidas antropométricas en niños, jóvenes, adultos etc. Aplica el método de la Somatoscopia en la construcción del modelo postural, identificando alteraciones y proponiendo entrenamientos preventivos para el cuidado postural$$,
        $$Tiene la capacidad de ejecuta el método antropométrico en la determinación de la valoración corporal. Aplica instrumentos especiales para la toma de medidas antropométricas en niños, jóvenes, adultos etc. Aplica el método de la Somatoscopia en la construcción del modelo postural, identificando alteraciones y proponiendo entrenamientos preventivos para el cuidado postural$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1138$$);

