    SELECT
        v_program_id, $$Entrenamiento de la velocidad$$, $$CEDS1235$$,
        3, 7,
        FALSE, $$specialty$$,
        $$El curso “Entrenamiento de la velocidad” tiene como resultado de aprendizaje la capacidad “Desarrolla programas de entrenamiento de la velocidad, en niños, jóvenes, adultos, deportistas y no deportistas, aplicando métodos, técnicas y procedimientos para provocar cambios o modificaciones a nivel de los grandes sistemas orgánicos, con seguridad y dominio”, contribuye al desarrollo de la competencia “Ejecutar programas de entrenamiento de las capacidades físicas o funcionales; resistencia, velocidad, fuerza, flexibilidad, generando adaptaciones internas y externas en el organismo a fin de contribuir a preservar y mantener la salud y una buena calidad de vida” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone actividades como el trabajo individual, trabajo cooperativo y análisis de casos; que posibiliten el conocimiento del concepto de la velocidad, factores determinantes de la velocidad, componentes, tipos de velocidad, Métodos de entrenamiento para la velocidad de Reacción. Métodos de entrenamiento: Aceleración y Máxima Velocidad Lanzada. Técnica de la carrera: Zancada Optima. La pliometría. fundamentos. desarrollo de la fuerza explosiva. Los multisaltos. Desarrolla programas de entrenamiento de la velocidad para niños, jóvenes y deportistas, demostrando seguridad y responsabilidad.$$,
        $$Ejecutar programas de entrenamiento de las capacidades físicas o funcionales; resistencia, velocidad, fuerza, flexibilidad, generando adaptaciones internas y externas en el organismo a fin de contribuir a preservar y mantener la salud y una buena calidad de vida$$,
        $$Desarrolla programas de entrenamiento de la velocidad, en niños, jóvenes, adultos, deportistas y no deportistas, aplicando métodos, técnicas y procedimientos para provocar cambios o modificaciones a nivel de los grandes sistemas orgánicos, con seguridad y dominio$$,
        $$Tiene la capacidad de desarrolla programas de entrenamiento de la velocidad, en niños, jóvenes, adultos, deportistas y no deportistas, aplicando métodos, técnicas y procedimientos para provocar cambios o modificaciones a nivel de los grandes sistemas orgánicos, con seguridad y dominio$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1235$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Control y prescripción de la actividad física$$, $$CEDS1232$$,
        3, 7,
        FALSE, $$specialty$$,
        $$El curso “Control y prescripción de la actividad física” tiene como resultado de aprendizaje la capacidad “Prescribir la actividad Física en estudiantes de Educación Básica Regular, así como en poblaciones sanas y con enfermedades no trasmisibles a fin de preservar y mantener la salud y coadyuvar a una buena calidad de vida.”, contribuye al desarrollo de la competencia “Ejecutar el ejercicio físico como un medio para preservar y mantener la salud usando sistemas de registro y procedimientos para monitorear, prescribir y controlar la actividad física en niños, jóvenes, adultos y adultos mayores; en poblaciones sanas y con enfermedades no trasmisibles coadyuvando a una mejor calidad de vida.” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone contenidos sobre la cuantificación de la actividad física, sistemas de registro y procedimientos para monitorear el nivel de actividad física y la familiarización con los principios generales de la prescripción de la actividad física incluyendo poblaciones sanas y con enfermedades no trasmisibles, prescripción del trabajo de resistencia para personas con sobrepeso, con obesidad, enfermedades cardiovasculares, respiratorias y mentales, como la ansiedad, el estrés, etc. Podrá diagnosticar, prescribir, controlar y valorar los resultados de la aplicación de un programa de actividad física en estudiantes y en diferentes poblaciones, con seguridad y responsabilidad$$,
        $$Ejecutar el ejercicio físico como un medio para preservar y mantener la salud usando sistemas de registro y procedimientos para monitorear, prescribir y controlar la actividad física en niños, jóvenes, adultos y adultos mayores; en poblaciones sanas y con enfermedades no trasmisibles coadyuvando a una mejor calidad de vida.$$,
        $$Prescribir la actividad Física en estudiantes de Educación Básica Regular, así como en poblaciones sanas y con enfermedades no trasmisibles a fin de preservar y mantener la salud y coadyuvar a una buena calidad de vida.$$,
        $$Tiene la capacidad de prescribir la actividad Física en estudiantes de Educación Básica Regular, así como en poblaciones sanas y con enfermedades no trasmisibles a fin de preservar y mantener la salud y coadyuvar a una buena calidad de vida.$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1232$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Didáctica de la natación$$, $$CEDS1234$$,
        4, 7,
        FALSE, $$specialty$$,
        $$El curso “Didáctica de la natación” tiene como resultado de aprendizaje la capacidad “Desarrolla el proceso enseñanza aprendizaje de los fundamentos técnicos y tácticos del deporte natación, haciendo uso de diversos enfoques, principios, métodos técnicas y procedimientos, para utilizarlos como insumos en la práctica de este deporte con seguridad y responsabilidad”, contribuye al desarrollo de la competencia “Ejecutar el proceso enseñanza aprendizaje de la Educación Física y de los deportes, aplicando enfoques, leyes, métodos, procedimientos y técnicas para el desarrollo de las habilidades motrices, la psicomotricidad, los juegos, la gimnasia aeróbica, las danzas peruanas, el ejercicio físico, etc.; en los niveles de la Educación Básica Regular, para niños, jóvenes, demostrando eficiencia profesional” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone actividades como el trabajo individual, trabajo cooperativo, prácticas dirigidas y experiencias de campo; que posibiliten el conocimiento del concepto de natación. Técnica de nado. Tipos de nados. Ejecuta el estilo crol y espalda. Describe la estructura del análisis mecánico de las fases de los movimientos del estilo crol y espalda. Aplica técnicas y Método de enseñanza de la partida para el estilo crol y espalda. Usa técnicas y métodos para la enseñanza del vueltas y virajes del estilo crol y espalda. Concepto de técnica de nado pecho y mariposa. Describe la estructura del análisis mecánico del estilo pecho y Mariposa. Aplica técnicas y métodos para la enseñanza de vueltas y virajes en el estilo crol y mariposa. Ejecuta técnicas de rescate acuático. Nados específicos, agarres, llaves, contra llaves, cargas, tomas técnicas de rescate en el medio acuático. Demuestra sólida formación pedagógica.$$,
        $$Ejecutar el proceso enseñanza aprendizaje de la Educación Física y de los deportes, aplicando enfoques, leyes, métodos, procedimientos y técnicas para el desarrollo de las habilidades motrices, la psicomotricidad, los juegos, la gimnasia aeróbica, las danzas peruanas, el ejercicio físico, etc.; en los niveles de la Educación Básica Regular, para niños, jóvenes, demostrando eficiencia profesional$$,
        $$Desarrolla el proceso enseñanza aprendizaje de los fundamentos técnicos y tácticos del deporte natación, haciendo uso de diversos enfoques, principios, métodos técnicas y procedimientos, para utilizarlos como insumos en la práctica de este deporte con seguridad y responsabilidad$$,
        $$Tiene la capacidad de desarrolla el proceso enseñanza aprendizaje de los fundamentos técnicos y tácticos del deporte natación, haciendo uso de diversos enfoques, principios, métodos técnicas y procedimientos, para utilizarlos como insumos en la práctica de este deporte con seguridad y responsabilidad$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1234$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
