    SELECT
        v_program_id, $$Evaluación de los aprendizajes$$, $$CEDE1017$$,
        3, 8,
        FALSE, $$specific$$,
        $$El curso de Evaluación de los Aprendizajes tiene como resultado de aprendizaje el desarrollo de la capacidad: “Evalúa el aprendizaje en el marco del enfoque formativo vigente en el contexto educativo, tomando en cuenta sus procesos y características, a fin de tomar decisiones y retroalimentar a los estudiantes en pro de los propósitos de aprendizaje” y que contribuye al desarrollo de la competencia “Gestiona al proceso formativo en los distintos niveles del sistema educativo a partir del conocimiento de las principales características biopsicosociales de los estudiantes, teorías del desarrollo humano, teorías psicológicas, modelos pedagógicos, paradigmas curriculares, teorías del aprendizaje y en función de las disciplinas antropología y social”. Es un curso de naturaleza teórico- práctica, enmarcado en el enfoque por competencias que posibilite una metodología activa en un entorno real de enseñanza y aprendizaje situando al estudiante como protagonista de su aprendizaje y el docente como facilitador del proceso formativo. Plantea actividades que posibiliten el conocimiento: Evaluación del aprendizaje como parte de la evaluación Educativa. Alcance conceptual, ejes epistémicos, principales definiciones, supuestos y problemáticas. La evaluación del aprendizaje: enfoques, objeto, dominio, niveles, características, funciones, tipos, clasificación y planeamiento del proceso de evaluación del aprendizaje. Técnicas e instrumentos de evaluación y el desarrollo de las habilidades: identifica que concepción y enfoque de evaluación maneja su docente. Diseña un instrumento de evaluación. Aplica el instrumento durante sus prácticas profesionales.$$,
        $$Gestiona al proceso formativo en los distintos niveles del sistema educativo a partir del conocimiento de las principales características biopsicosociales de los estudiantes, teorías del desarrollo humano, teorías psicológicas, modelos pedagógicos, paradigmas curriculares, teorías del aprendizaje y en función de las disciplinas antropología y social$$,
        $$Evalúa el aprendizaje en el marco del enfoque formativo vigente en el contexto educativo, tomando en cuenta sus procesos y características, a fin de tomar decisiones y retroalimentar a los estudiantes en pro de los propósitos de aprendizaje$$,
        $$Tiene la capacidad de evalúa el aprendizaje en el marco del enfoque formativo vigente en el contexto educativo, tomando en cuenta sus procesos y características, a fin de tomar decisiones y retroalimentar a los estudiantes en pro de los propósitos de aprendizaje$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDE1017$$);

