    SELECT
        v_program_id, $$Técnicas e instrumentos de investigación cualitativa$$, $$CEDE1015$$,
        3, 8,
        FALSE, $$specific$$,
        $$El curso de “Técnicas e Instrumentos de Investigación Cualitativa” tiene como resultado de aprendizaje la capacidad de “Diseña los principales instrumentos de investigación con enfoques cualitativo y/o de investigación acción para recabar datos cualitativos, considerando sus objetivos de investigación” teniendo como competencia “Desarrolla investigaciones educativas en base a los diversos paradigmas, metodologías y enfoques investigativos, en los distintos ámbitos de su actuación, buscando contribuir con alternativas de solución, orientadas a la mejora de la educación”, según perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Plantea actividades que posibiliten el conocimiento de: Recolección de datos con enfoques cualitativos, unidades de análisis, técnicas de observación, entrevista, grupos de enfoque, criterios de validación de instrumentos, técnicas para la sistematización de la información, análisis de los datos cualitativos, considerando los diversos contextos de la investigación; y desarrolla las habilidades de: analiza y aplica instrumentos de investigación, determina y aplica técnicas para la sistematización de la información, adapta diseño cualitativos.$$,
        $$Desarrolla investigaciones educativas en base a los diversos paradigmas, metodologías y enfoques investigativos, en los distintos ámbitos de su actuación, buscando contribuir con alternativas de solución, orientadas a la mejora de la educación$$,
        $$Diseña los principales instrumentos de investigación con enfoques cualitativo y/o de investigación acción para recabar datos cualitativos, considerando sus objetivos de investigación$$,
        $$Tiene la capacidad de diseña los principales instrumentos de investigación con enfoques cualitativo y/o de investigación acción para recabar datos cualitativos, considerando sus objetivos de investigación$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDE1015$$);

    INSERT INTO courses
        (program_id, name, code, credits, cycle, is_common, scope,
         sumilla, competencia_egreso, resultado_aprendizaje, capacidad)
    SELECT
        v_program_id, $$Desarrollo Profesional IV: Innovación didáctica$$, $$CEDE1011$$,
        3, 8,
        FALSE, $$specific$$,
        $$El curso de Desarrollo Profesional IV: Innovación didáctica tiene como resultado de aprendizaje el desarrollo de la capacidad “Diseña estrategias de enseñanza y aprendizaje, inclusivas y situadas, utilizando en el aula los principios de la docencia reflexiva y de la Investigación-Acción, para mejorar su práctica, a través de la sistematización de su experiencia docente”, que contribuye a la competencia específica “Promueve sesiones de aprendizaje situados, considerando el contexto y la cultura escolar, utilizando los principios de la docencia reflexiva para la mejora de su práctica; evaluando los procesos de gestión institucional, y proponiendo mejoras de su práctica docente, utilizando la metodología de Investigación Acción Pedagógica”. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Desarrolla actividades que posibiliten el conocimiento de principios educativos de la enseñanza situada, estrategias para desarrollar el aprendizaje situado, diagnóstico: el contexto cultural y las características e intereses de los estudiantes de secundaria, diseño de planeaciones fundamentadas, intervención didáctica: Conocimiento en la acción y reflexión en la acción, recuperación de las evidencias de su desempeño docente, clasificación y análisis de las evidencias, propuestas de mejora de su práctica docente futura. El producto acreditable consiste en la elaboración de un informe de prácticas docentes (sesiones de aprendizaje) como producto y la ejecución de un panel de discusión en el que los estudiantes presentan sus reflexiones acerca de sus prácticas docentes, así como sus propuestas de mejora y de innovación para la docencia en el siguiente semestre$$,
        $$Promueve sesiones de aprendizaje situados, considerando el contexto y la cultura escolar, utilizando los principios de la docencia reflexiva para la mejora de su práctica; evaluando los procesos de gestión institucional, y proponiendo mejoras de su práctica docente, utilizando la metodología de Investigación Acción Pedagógica$$,
        $$Diseña estrategias de enseñanza y aprendizaje, inclusivas y situadas, utilizando en el aula los principios de la docencia reflexiva y de la Investigación-Acción, para mejorar su práctica, a través de la sistematización de su experiencia docente$$,
        $$Tiene la capacidad de diseña estrategias de enseñanza y aprendizaje, inclusivas y situadas, utilizando en el aula los principios de la docencia reflexiva y de la Investigación-Acción, para mejorar su práctica, a través de la sistematización de su experiencia docente$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDE1011$$);

