    SELECT
        v_program_id, $$El Ejercicio físico en el Marco de la Salud$$, $$CEDS1277$$,
        3, 8,
        FALSE, $$specialty$$,
        $$El curso “El ejercicio físico en el marco de la salud” tiene como resultado de aprendizaje la capacidad “Explica la salud y sus efectos beneficiosos de la actividad física, determinando estrategias y valoración de la actividad física para el bienestar subjetivo, para la salud mental, sobre el sueño, etc. Riesgos del ejercicio físico.”, contribuye al desarrollo de la competencia “Ejecutar el ejercicio físico como un medio para preservar y mantener la salud usando sistemas de registro y procedimientos para monitorear, prescribir y controlar la actividad física en niños, jóvenes, adultos y adultos mayores; en poblaciones sanas y con enfermedades no trasmisibles coadyuvando a una mejor calidad de vida.” del perfil de egreso. Es un curso de naturaleza teórico-práctica, enmarcada en el enfoque por competencias que posibilita una metodología activa y participativa en un entorno real de enseñanza aprendizaje situando al estudiante como protagonista de su aprendizaje y al docente como facilitador del proceso formativo. Propone contenidos alineadas a la actividad física, ejercicio físico, relación entre actividad física y salud cardiovascular, diabetes, obesidad, síndrome metabólico, cáncer, salud ósea y muscular, salud mental. Recomendaciones para mejorar los estilos de vida y actividad física considerando riesgos del ejercicio físico. Determina estrategias de medición y valoración de la actividad física para el bienestar subjetivo, la salud mental, el sueño, etc., con seguridad y responsabilidad.$$,
        $$Ejecutar el ejercicio físico como un medio para preservar y mantener la salud usando sistemas de registro y procedimientos para monitorear, prescribir y controlar la actividad física en niños, jóvenes, adultos y adultos mayores; en poblaciones sanas y con enfermedades no trasmisibles coadyuvando a una mejor calidad de vida.$$,
        $$Explica la salud y sus efectos beneficiosos de la actividad física, determinando estrategias y valoración de la actividad física para el bienestar subjetivo, para la salud mental, sobre el sueño, etc. Riesgos del ejercicio físico.$$,
        $$Tiene la capacidad de explica la salud y sus efectos beneficiosos de la actividad física, determinando estrategias y valoración de la actividad física para el bienestar subjetivo, para la salud mental, sobre el sueño, etc. Riesgos del ejercicio físico.$$
    WHERE NOT EXISTS (SELECT 1 FROM courses WHERE program_id = v_program_id AND code = $$CEDS1277$$);

